//! ProcureToPay flow implementation
//!
//! Generated by metaphor-schema
//!
//! A material request is sourced and committed as a Purchase Order; the confirmed PO drives inventory
//! to receive goods (asset post) and billing to raise the Purchase Invoice (A/P post); the PO
//! completes when fully received AND billed.

use serde::{Deserialize, Serialize};
use std::sync::Arc;
use chrono;
use backbone_core::flow::{WorkflowStep, WorkflowContext};

/// Error type for flow execution
#[derive(Debug, Clone, thiserror::Error)]
pub enum FlowError {
    #[error("No current step to execute")]
    NoCurrentStep,

    #[error("Step execution failed: {0}")]
    StepFailed(String),

    #[error("Condition evaluation failed: {0}")]
    ConditionFailed(String),

    #[error("Compensation failed: {0}")]
    CompensationFailed(String),

    #[error("Flow timed out")]
    Timeout,

    #[error("Flow cancelled")]
    Cancelled,

    #[error("Invalid state transition: {from} -> {to}")]
    InvalidTransition { from: String, to: String },
}

/// Execution status for ProcureToPay flow
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum ProcureToPayFlowStatus {
    /// Flow is pending execution
    Pending,
    /// Flow is currently running
    Running,
    /// Flow is waiting for an event or condition
    Waiting,
    /// Flow completed successfully
    Completed,
    /// Flow failed
    Failed,
    /// Flow was cancelled
    Cancelled,
    /// Flow is compensating (rolling back)
    Compensating,
}

/// Steps in ProcureToPay flow
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum ProcureToPayFlowStep {
    /// request_receipt
    RequestReceipt,
    /// await_receipt
    AwaitReceipt,
    /// await_billing
    AwaitBilling,
    /// done
    Done,
    /// rejected
    Rejected,
}

/// Instance of ProcureToPay flow execution
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ProcureToPayFlowInstance {
    /// Unique instance ID
    pub id: String,
    /// Current status
    pub status: ProcureToPayFlowStatus,
    /// Current step
    pub current_step: Option<ProcureToPayFlowStep>,
    /// Flow context (variables)
    pub context: serde_json::Value,
    /// Completed steps
    pub completed_steps: Vec<ProcureToPayFlowStep>,
    /// Error if failed
    pub error: Option<String>,
    /// Created timestamp
    pub created_at: chrono::DateTime<chrono::Utc>,
    /// Updated timestamp
    pub updated_at: chrono::DateTime<chrono::Utc>,
}

impl ProcureToPayFlowInstance {
    /// Create a new flow instance
    pub fn new(id: impl Into<String>) -> Self {
        let now = chrono::Utc::now();
        Self {
            id: id.into(),
            status: ProcureToPayFlowStatus::Pending,
            current_step: None,
            context: serde_json::json!({}),
            completed_steps: Vec::new(),
            error: None,
            created_at: now,
            updated_at: now,
        }
    }

    /// Check if flow is complete
    pub fn is_complete(&self) -> bool {
        matches!(
            self.status,
            ProcureToPayFlowStatus::Completed | ProcureToPayFlowStatus::Failed | ProcureToPayFlowStatus::Cancelled
        )
    }

    /// Check if flow is running
    pub fn is_running(&self) -> bool {
        matches!(
            self.status,
            ProcureToPayFlowStatus::Running | ProcureToPayFlowStatus::Waiting
        )
    }

    /// Set a context variable
    pub fn set_context(&mut self, key: &str, value: serde_json::Value) {
        if let serde_json::Value::Object(ref mut map) = self.context {
            map.insert(key.to_string(), value);
        }
        self.updated_at = chrono::Utc::now();
    }

    /// Get a context variable
    pub fn get_context(&self, key: &str) -> Option<&serde_json::Value> {
        if let serde_json::Value::Object(ref map) = self.context {
            map.get(key)
        } else {
            None
        }
    }
}

// Phase 1: FlowInstance satisfies backbone_core::flow::WorkflowContext.
// The entity() accessor requires the entity to be carried in the instance;
// add `pub entity: ProcureToPay` in the // <<< CUSTOM section and remove the todo!.
#[allow(unused_variables)]
impl WorkflowContext<ProcureToPayFlowInstance> for ProcureToPayFlowInstance {
    fn entity(&self) -> &ProcureToPayFlowInstance { self }
    fn set_var(&mut self, key: &str, value: serde_json::Value) {
        self.set_context(key, value);
    }
    fn get_var(&self, key: &str) -> Option<&serde_json::Value> {
        self.get_context(key)
    }
}

/// Step handler trait for ProcureToPay flow
#[async_trait::async_trait]
pub trait ProcureToPayStepHandler: Send + Sync {
    /// Handle request_receipt step
    async fn handle_request_receipt(
        &self,
        instance: &mut ProcureToPayFlowInstance,
    ) -> Result<Option<ProcureToPayFlowStep>, FlowError>;

    /// Handle await_receipt step
    async fn handle_await_receipt(
        &self,
        instance: &mut ProcureToPayFlowInstance,
    ) -> Result<Option<ProcureToPayFlowStep>, FlowError>;

    /// Handle await_billing step
    async fn handle_await_billing(
        &self,
        instance: &mut ProcureToPayFlowInstance,
    ) -> Result<Option<ProcureToPayFlowStep>, FlowError>;

    /// Handle terminal step done
    async fn handle_done(
        &self,
        instance: &mut ProcureToPayFlowInstance,
    ) -> Result<(), FlowError>;

    /// Handle terminal step rejected
    async fn handle_rejected(
        &self,
        instance: &mut ProcureToPayFlowInstance,
    ) -> Result<(), FlowError>;

}

/// Executor for ProcureToPay flow
pub struct ProcureToPayFlowExecutor<H: ProcureToPayStepHandler> {
    handler: Arc<H>,
}

impl<H: ProcureToPayStepHandler> ProcureToPayFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self { handler }
    }

    /// Start a new flow instance
    pub async fn start(&self, instance_id: impl Into<String>) -> Result<ProcureToPayFlowInstance, FlowError> {
        let mut instance = ProcureToPayFlowInstance::new(instance_id);
        instance.status = ProcureToPayFlowStatus::Running;
        instance.current_step = Some(ProcureToPayFlowStep::RequestReceipt);
        Ok(instance)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut ProcureToPayFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            ProcureToPayFlowStep::RequestReceipt => {
                self.handler.handle_request_receipt(instance).await?
            }
            ProcureToPayFlowStep::AwaitReceipt => {
                self.handler.handle_await_receipt(instance).await?
            }
            ProcureToPayFlowStep::AwaitBilling => {
                self.handler.handle_await_billing(instance).await?
            }
            ProcureToPayFlowStep::Done => {
                self.handler.handle_done(instance).await?;
                None // Terminal step
            }
            ProcureToPayFlowStep::Rejected => {
                self.handler.handle_rejected(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = ProcureToPayFlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut ProcureToPayFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != ProcureToPayFlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut ProcureToPayFlowInstance) {
        instance.status = ProcureToPayFlowStatus::Cancelled;
        instance.updated_at = chrono::Utc::now();
    }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut ProcureToPayFlowInstance, error: impl Into<String>) {
        instance.status = ProcureToPayFlowStatus::Failed;
        instance.error = Some(error.into());
        instance.updated_at = chrono::Utc::now();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = ProcureToPayFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, ProcureToPayFlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = ProcureToPayFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = ProcureToPayFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = ProcureToPayFlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = ProcureToPayFlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}